package main

import (
    "encoding/gob"
    "fmt"
    "os"
    "path/filepath"
    "sync"
    "time"
)

type UserPreferences struct {
    Theme    string
    Language string
    Timezone string
}

type Permissions struct {
    CanRead   bool
    CanWrite  bool
    CanDelete bool
    IsAdmin   bool
}

type Session struct {
    SessionID   string
    UserID      int
    Preferences UserPreferences
    Permissions Permissions
    CreatedAt   time.Time
    LastAccess  time.Time
}

type SessionManager struct {
    sessions    map[string]*Session
    mu          sync.RWMutex
    storagePath string
}

func NewSessionManager(storagePath string) *SessionManager {
    if err := os.MkdirAll(storagePath, 0755); err != nil {
        panic(err)
    }
    
    return &SessionManager{
        sessions:    make(map[string]*Session),
        storagePath: storagePath,
    }
}

func (sm *SessionManager) CreateSession(sessionID string, userID int, prefs UserPreferences, perms Permissions) *Session {
    sm.mu.Lock()
    defer sm.mu.Unlock()

    session := &Session{
        SessionID:   sessionID,
        UserID:      userID,
        Preferences: prefs,
        Permissions: perms,
        CreatedAt:   time.Now(),
        LastAccess:  time.Now(),
    }

    sm.sessions[sessionID] = session
    sm.saveSessionToDisk(session)
    
    return session
}

func (sm *SessionManager) GetSession(sessionID string) (*Session, error) {
    sm.mu.RLock()
    session, exists := sm.sessions[sessionID]
    sm.mu.RUnlock()

    if exists {
        sm.mu.Lock()
        session.LastAccess = time.Now()
        sm.mu.Unlock()
        sm.saveSessionToDisk(session)
        return session, nil
    }

    session, err := sm.loadSessionFromDisk(sessionID)
    if err != nil {
        return nil, fmt.Errorf("session not found: %w", err)
    }

    sm.mu.Lock()
    session.LastAccess = time.Now()
    sm.sessions[sessionID] = session
    sm.mu.Unlock()
    
    sm.saveSessionToDisk(session)
    
    return session, nil
}

func (sm *SessionManager) UpdateSession(sessionID string, prefs *UserPreferences, perms *Permissions) error {
    session, err := sm.GetSession(sessionID)
    if err != nil {
        return err
    }

    sm.mu.Lock()
    defer sm.mu.Unlock()

    if prefs != nil {
        session.Preferences = *prefs
    }
    if perms != nil {
        session.Permissions = *perms
    }
    session.LastAccess = time.Now()

    return sm.saveSessionToDisk(session)
}

func (sm *SessionManager) DeleteSession(sessionID string) error {
    sm.mu.Lock()
    defer sm.mu.Unlock()

    delete(sm.sessions, sessionID)
    
    filename := filepath.Join(sm.storagePath, sessionID+".gob")
    return os.Remove(filename)
}

func (sm *SessionManager) saveSessionToDisk(session *Session) error {
    filename := filepath.Join(sm.storagePath, session.SessionID+".gob")
    
    file, err := os.Create(filename)
    if err != nil {
        return fmt.Errorf("failed to create session file: %w", err)
    }
    defer file.Close()

    encoder := gob.NewEncoder(file)
    if err := encoder.Encode(session); err != nil {
        return fmt.Errorf("failed to encode session: %w", err)
    }

    return nil
}

func (sm *SessionManager) loadSessionFromDisk(sessionID string) (*Session, error) {
    filename := filepath.Join(sm.storagePath, sessionID+".gob")
    
    file, err := os.Open(filename)
    if err != nil {
        return nil, fmt.Errorf("failed to open session file: %w", err)
    }
    defer file.Close()

    var session Session
    decoder := gob.NewDecoder(file)
    if err := decoder.Decode(&session); err != nil {
        return nil, fmt.Errorf("failed to decode session: %w", err)
    }

    return &session, nil
}

func (sm *SessionManager) LoadAllSessions() error {
    sm.mu.Lock()
    defer sm.mu.Unlock()

    files, err := filepath.Glob(filepath.Join(sm.storagePath, "*.gob"))
    if err != nil {
        return fmt.Errorf("failed to list session files: %w", err)
    }

    for _, filename := range files {
        file, err := os.Open(filename)
        if err != nil {
            continue
        }

        var session Session
        decoder := gob.NewDecoder(file)
        if err := decoder.Decode(&session); err != nil {
            file.Close()
            continue
        }
        file.Close()

        sm.sessions[session.SessionID] = &session
    }

    return nil
}

func (sm *SessionManager) CleanupExpiredSessions(maxAge time.Duration) error {
    sm.mu.Lock()
    defer sm.mu.Unlock()

    now := time.Now()
    for sessionID, session := range sm.sessions {
        if now.Sub(session.LastAccess) > maxAge {
            delete(sm.sessions, sessionID)
            filename := filepath.Join(sm.storagePath, sessionID+".gob")
            os.Remove(filename)
        }
    }

    return nil
}

